class AllOne {
    private Map<String, Integer> countMap;
    private TreeMap<Integer, Set<String>> treeMap;

    public AllOne() {
        countMap = new HashMap<>();
        treeMap = new TreeMap<>();
    }

    public void inc(String key) {
        countMap.put(key, countMap.getOrDefault(key, 0) + 1);
        updateTreeMap(key);
    }

    public void dec(String key) {
        int count = countMap.get(key) - 1;
        if (count > 0) {
            countMap.put(key, count);
            updateTreeMap(key);
        } else {
            countMap.remove(key);
        }
    }

    public String getMaxKey() {
        return treeMap.getOrDefault(treeMap.lastKey(), new HashSet<>()).iterator().next();
    }

    public String getMinKey() {
        return treeMap.getOrDefault(treeMap.firstKey(), new HashSet<>()).iterator().next();
    }

    private void updateTreeMap(String key) {
        int count = countMap.get(key);
        treeMap.computeIfAbsent(count, k -> new HashSet<>()).add(key);
        treeMap.computeIfAbsent(count - 1, k -> new HashSet<>()).remove(key);
    }
}
